properties.entry:
SEQUENCED TEMPORAL (
  WITH q AS (SELECT a FROM TEMP_TEST WITH TIME(T_BEGIN, T_END))
  SELECT * FROM q
  WHERE a != 2
);

SEQUENCED TEMPORAL (
  WITH q AS (SELECT a, b FROM TEMP_TEST WITH TIME(T_BEGIN, T_END))
  SELECT r1.a, r2.a AS x
  FROM q r1, q r2
  WHERE r1.a = r2.b
);

SEQUENCED TEMPORAL (
  WITH maxa AS (SELECT max(a) AS maxa  FROM temp_test WITH TIME(T_BEGIN, T_END))
  SELECT r.a, r.b
  FROM maxa, temp_test WITH TIME(T_BEGIN, T_END) r
  WHERE maxa.maxa = r.a
  );
